SELECT recommended_size, customer_height_cm, customer_weight_kg, confidence_score
FROM customer_fit_recommendations
WHERE recommendation_date = '2023-10-02T15:00:00Z';

SELECT recommended_size, recommendation_date, AVG(confidence_score) AS avg_confidence
FROM customer_fit_recommendations
GROUP BY recommended_size, recommendation_date;

SELECT product_name
FROM products
WHERE is_active = 1 AND brand_id = (SELECT brand_id FROM brands WHERE brand_name = 'Brand A');
